#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100
#define MAX_F 10000

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        double P[N];
        int F[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf", &P[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &F[i]);
        }
        double S;
        scanf("%lf", &S);
        double dp[N + 1][N * MAX_F + 1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= N * MAX_F; j++) {
                dp[i][j] = 0;
            }
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= N * MAX_F; j++) {
                if (j >= F[i - 1]) {
                    dp[i][j] = (P[i - 1] * (1 - P[i - 1]) + (1 - P[i - 1]) * P[i - 1]) * dp[i - 1][j - F[i - 1]] + P[i - 1] * (1 - P[i - 1]);
                }
                dp[i][j] = (dp[i][j] > dp[i - 1][j]) ? dp[i][j] : dp[i - 1][j];
            }
        }
        int max_sum = 0;
        for (int i = 0; i <= N * MAX_F; i++) {
            if (dp[N][i] < S) {
                max_sum = (max_sum > i) ? max_sum : i;
            }
        }
        printf("Case %d: %d\n", T - T + 1, max_sum);
    }
    return 0;
}

